using namespace std;

struct TreeNode {
    int val;
    vector<TreeNode*> children;
    TreeNode(int x) : val(x) {}
};

TreeNode* buildTree(int n, const int c[]) {
    // Validate input
    if (n <= 0 || c == nullptr) {
        cerr << "Invalid input" << endl;
        return nullptr;
    }

    // Check for negative values or indices out of bounds
    for (int i = 0; i < 2 * n; ++i) {
        if (c[i] < -1 || c[i] >= n) {
            cerr << "Invalid child index" << endl;
            return nullptr;
        }
    }

    vector<unique_ptr<TreeNode>> nodes(n);
    for (int i = 0; i < n; ++i) {
        nodes[i] = make_unique<TreeNode>(i + 1);
    }

    for (int i = 0; i < n; ++i) {
        int start = 2 * i + 1;
        while (c[start] != -1) {
            int childIndex = c[start] - 1;
            nodes[i]->children.push_back(nodes[childIndex].get());
            start++;
        }
    }

    return nodes[0].release();
}

